window.YPP=window.YPP||{};window.YPP.features=window.YPP.features||{};window.YPP.features.FolderStorage=class{constructor(){this.STORAGE_KEY="ypp_subscription_folders",this.folders={Favorites:[],Tech:[],Gaming:[]},this.folderConfig={}}async load(){var s;try{const e=await chrome.storage.local.get([this.STORAGE_KEY,"ypp_folder_config"]);e[this.STORAGE_KEY]?this.folders=e[this.STORAGE_KEY]:await this.save(),this.folderConfig=e.ypp_folder_config||{}}catch{(s=window.YPP.Utils)==null||s.log("Failed to load subscription folders","FolderStorage","error")}}async save(){var s;try{await chrome.storage.local.set({[this.STORAGE_KEY]:this.folders,ypp_folder_config:this.folderConfig})}catch{(s=window.YPP.Utils)==null||s.log("Failed to save subscription folders","FolderStorage","error")}}addFolder(s){return!s||this.folders[s]?!1:(this.folders[s]=[],this.save(),!0)}deleteFolder(s){return this.folders[s]?(delete this.folders[s],this.folderConfig[s]&&delete this.folderConfig[s],this.save(),!0):!1}addChannelToFolder(s,e){return!this.folders[e]||this.folders[e].includes(s)?!1:(this.folders[e].push(s),this.save(),!0)}removeChannelFromFolder(s,e){if(!this.folders[e])return!1;const t=this.folders[e].indexOf(s);return t===-1?!1:(this.folders[e].splice(t,1),this.save(),!0)}};
